"use server";

import fs from 'fs';
import path from 'path';
import { revalidatePath } from "next/cache";
import { SiteSettings, Category, Review, Product, Collection, Homepage, HomepageHero, HomepagePromo, OrderStatus } from "@/lib/types";
import { supabase } from "@/lib/supabase";

// Site Settings
export async function getSiteSettings(): Promise<SiteSettings> {
    let { data, error } = await supabase
        .from('site_settings')
        .select('*')
        .eq('id', 1)
        .single();

    // Auto-sync store name if it's the old one
    if (data && data.store_name === "REHAM") {
        const { data: updated } = await supabase.from('site_settings').upsert({
            id: 1,
            store_name: "SHOPOHOLIC"
        }).select().single();
        if (updated) data = updated;
    }

    if (!data) return { storeName: "SHOPOHOLIC" } as SiteSettings;

    return {
        storeName: data.store_name,
        storeDescription: data.store_description,
        contactEmail: data.contact_email,
        contactPhone: data.contact_phone,
        address: data.address,
        currency: data.currency,
        currencySymbol: data.currency_symbol,
        maintenanceMode: data.maintenance_mode,
        footerText: data.footer_text,
        taxRate: parseFloat(data.tax_rate || 0),
        shippingFee: parseFloat(data.shipping_fee || 0),
        freeShippingThreshold: parseFloat(data.free_shipping_threshold || 0),
        socialLinks: data.social_links // social_links is JSON, matches interface structure
    } as SiteSettings;
}

export async function updateSiteSettings(settings: SiteSettings) {
    console.log("[ACTION] Updating site settings...");
    try {
        const { error } = await supabase
            .from('site_settings')
            .upsert({
                id: 1,
                store_name: settings.storeName,
                store_description: settings.storeDescription,
                contact_email: settings.contactEmail,
                contact_phone: settings.contactPhone,
                address: settings.address,
                currency: settings.currency,
                currency_symbol: settings.currencySymbol,
                maintenance_mode: settings.maintenanceMode,
                social_links: settings.socialLinks,
                footer_text: settings.footerText,
                tax_rate: settings.taxRate,
                shipping_fee: settings.shippingFee,
                free_shipping_threshold: settings.freeShippingThreshold,
                updated_at: new Date().toISOString()
            });

        if (error) throw error;

        revalidatePath('/', 'layout');
        revalidatePath('/admin/settings');
        return { success: true };
    } catch (error) {
        console.error("Error updating site settings:", error);
        throw new Error("Failed to update site settings");
    }
}

// Categories
export async function getCategories() {
    console.log("[ACTION] Fetching categories...");
    const { data, error } = await supabase
        .from('categories')
        .select('*')
        .order('label');

    if (error) {
        console.error("Error fetching categories:", error);
        return [];
    }
    return data;
}

export async function getCategoryProductCounts() {
    const { data, error } = await supabase
        .from('products')
        .select('category');

    if (error) return {};

    const counts: Record<string, number> = {};
    data.forEach(p => {
        counts[p.category] = (counts[p.category] || 0) + 1;
    });

    return counts;
}

export async function addCategory(category: { label: string, type?: string }) {
    console.log(`[ACTION] Adding category: ${category.label}`);
    try {
        const slug = category.label.toLowerCase().trim().replace(/[^a-z0-9]+/g, '-');
        const uniqueId = `${slug}-${Math.random().toString(36).substr(2, 5)}`;

        const { data, error } = await supabase
            .from('categories')
            .insert([{ id: uniqueId, label: category.label, type: category.type }])
            .select()
            .single();

        if (error) throw error;

        revalidatePath('/', 'layout');
        revalidatePath('/shop');

        return { success: true, category: data };
    } catch (error) {
        console.error("Error adding category:", error);
        throw new Error("Failed to add category");
    }
}

export async function deleteCategory(categoryId: string) {
    console.log(`[ACTION] Deleting category: ${categoryId}`);
    try {
        const { error } = await supabase
            .from('categories')
            .delete()
            .eq('id', categoryId);

        if (error) throw error;

        revalidatePath('/', 'layout');
        revalidatePath('/admin/inventory');
        return { success: true };
    } catch (error) {
        console.error("Error deleting category:", error);
        throw new Error("Failed to delete category");
    }
}

export async function updateCategoryServer(id: string, data: Partial<Category>) {
    try {
        const { error } = await supabase
            .from('categories')
            .update({ label: data.label, type: data.type })
            .eq('id', id);

        if (error) throw error;
        revalidatePath('/', 'layout');
        return { success: true };
    } catch (error) {
        console.error("Error updating category:", error);
        throw new Error("Failed to update category");
    }
}

export async function renameCategoryGroup(oldName: string, newName: string) {
    try {
        const { error } = await supabase
            .from('categories')
            .update({ type: newName })
            .eq('type', oldName);

        if (error) throw error;
        revalidatePath('/', 'layout');
        return { success: true };
    } catch (error) {
        console.error("Error renaming category group:", error);
        throw new Error("Failed to rename category group");
    }
}

// Reviews
export async function addProductReview(productId: string, input: any) {
    try {
        const data = input instanceof FormData ? {
            userName: input.get("userName") as string,
            rating: Number(input.get("rating")),
            comment: input.get("comment") as string,
            date: (input.get("date") as string) || new Date().toISOString()
        } : input;

        const newReview = {
            id: `rev-${Date.now()}`,
            product_id: productId,
            user_name: data.userName,
            rating: data.rating,
            comment: data.comment,
            verified: true,
            created_at: data.date || new Date().toISOString()
        };

        const { error } = await supabase
            .from('reviews')
            .insert([newReview]);

        if (error) throw error;

        // Update product aggregate rating
        const { data: reviews } = await supabase
            .from('reviews')
            .select('rating')
            .eq('product_id', productId);

        if (reviews && reviews.length > 0) {
            const avg = reviews.reduce((sum, r) => sum + r.rating, 0) / reviews.length;
            await supabase
                .from('products')
                .update({ 
                    rating: Number(avg.toFixed(1)), 
                    reviews_count: reviews.length 
                })
                .eq('id', productId);
        }

        revalidatePath(`/shop/${productId}`);
        revalidatePath('/admin/inventory');

        return { success: true };
    } catch (error) {
        console.error("Error adding review:", error);
        throw new Error("Failed to add review");
    }
}

export async function deleteProductReview(productId: string, reviewId: string) {
    try {
        const { error } = await supabase
            .from('reviews')
            .delete()
            .eq('id', reviewId);

        if (error) throw error;

        // Recalculate rating
        const { data: reviews } = await supabase
            .from('reviews')
            .select('rating')
            .eq('product_id', productId);

        let avg = 0;
        let count = 0;
        if (reviews && reviews.length > 0) {
            avg = reviews.reduce((sum, r) => sum + r.rating, 0) / reviews.length;
            count = reviews.length;
        }

        await supabase
            .from('products')
            .update({ 
                rating: Number(avg.toFixed(1)), 
                reviews_count: count 
            })
            .eq('id', productId);

        revalidatePath(`/shop/${productId}`);
        revalidatePath('/admin/inventory');
        return { success: true };
    } catch (error) {
        console.error("Error deleting review:", error);
        throw new Error("Failed to delete review");
    }
}

// Utility for image saving to Supabase Storage
async function saveFile(file: File, prefix: string = "") {
    if (!file || file.size === 0) return null;

    try {
        const timestamp = Date.now();
        const safeName = file.name.replace(/[^a-z0-9.]/gi, '_').toLowerCase();
        const filename = `${prefix}${timestamp}-${safeName}`;

        const { data, error } = await supabase.storage
            .from('product-images')
            .upload(filename, file);

        if (error) throw error;

        const { data: { publicUrl } } = supabase.storage
            .from('product-images')
            .getPublicUrl(filename);

        return publicUrl;
    } catch (error) {
        console.error("Error saving file to Supabase:", error);
        return null;
    }
}

// Product Management
export async function addProduct(formData: FormData) {
    console.log("[ACTION] Adding new product...");
    try {
        const id = `prod-${Date.now()}`;
        const name = formData.get("name") as string;
        const price = parseFloat(formData.get("price") as string);
        const discountPrice = formData.get("discountPrice") ? parseFloat(formData.get("discountPrice") as string) : null;
        const description = formData.get("description") as string || "";
        const category = formData.get("category") as string;
        const type = formData.get("type") as string || "";

        const activeImageIds = formData.getAll("activeImageIds") as string[];
        const imageVariants: any[] = [];
        const imageUrls: string[] = [];

        for (const imageId of activeImageIds) {
            const file = formData.get(`image_${imageId}`) as File | null;
            const existingUrl = formData.get(`existing_image_${imageId}`) as string | null;
            const color = formData.get(`color_${imageId}`) as string;
            const sizesRaw = formData.get(`sizes_${imageId}`) as string;
            const sizesArr = JSON.parse(sizesRaw);

            let url = existingUrl;
            if (file && file.size > 0) {
                const savedUrl = await saveFile(file);
                if (savedUrl) url = savedUrl;
            }

            if (url) {
                imageUrls.push(url);
                sizesArr.forEach((s: any) => {
                    imageVariants.push({
                        url,
                        color,
                        size: s.size,
                        quantity: s.quantity || 0
                    });
                });
            }
        }

        const { error } = await supabase
            .from('products')
            .insert([{
                id,
                name,
                description,
                price,
                discount_price: discountPrice,
                category,
                type,
                images: [...new Set(imageUrls)],
                image_variants: imageVariants,
                sizes: [...new Set(imageVariants.map(v => v.size))],
                colors: [...new Set(imageVariants.map(v => v.color).filter(Boolean))],
                stock: imageVariants.reduce((sum, v) => sum + (v.quantity || 0), 0)
            }]);

        if (error) throw error;

        revalidatePath("/admin/inventory");
        revalidatePath("/shop");
        revalidatePath("/");

        return { success: true, id };
    } catch (error) {
        console.error("Error adding product:", error);
        throw new Error("Failed to add product");
    }
}

export async function updateProduct(formData: FormData) {
    const productId = formData.get("productId") as string;
    console.log(`[ACTION] Updating product ${productId}...`);
    try {
        const name = formData.get("name") as string;
        const price = parseFloat(formData.get("price") as string);
        const discountPrice = formData.get("discountPrice") ? parseFloat(formData.get("discountPrice") as string) : null;
        const description = formData.get("description") as string || "";
        const category = formData.get("category") as string;
        const type = formData.get("type") as string || "";

        const activeImageIds = formData.getAll("activeImageIds") as string[];
        const imageVariants: any[] = [];
        const imageUrls: string[] = [];

        for (const imageId of activeImageIds) {
            const file = formData.get(`image_${imageId}`) as File | null;
            const existingUrl = formData.get(`existing_image_${imageId}`) as string | null;
            const color = formData.get(`color_${imageId}`) as string;
            const sizesRaw = formData.get(`sizes_${imageId}`) as string;
            const sizesArr = JSON.parse(sizesRaw);

            let url = existingUrl;
            if (file && file.size > 0) {
                const savedUrl = await saveFile(file);
                if (savedUrl) url = savedUrl;
            }

            if (url) {
                imageUrls.push(url);
                sizesArr.forEach((s: any) => {
                    imageVariants.push({
                        url,
                        color,
                        size: s.size,
                        quantity: s.quantity || 0
                    });
                });
            }
        }

        const { error } = await supabase
            .from('products')
            .update({
                name,
                description,
                price,
                discount_price: discountPrice,
                category,
                type,
                images: [...new Set(imageUrls)],
                image_variants: imageVariants,
                sizes: [...new Set(imageVariants.map(v => v.size))],
                colors: [...new Set(imageVariants.map(v => v.color).filter(Boolean))],
                stock: imageVariants.reduce((sum, v) => sum + (v.quantity || 0), 0)
            })
            .eq('id', productId);

        if (error) throw error;

        revalidatePath("/admin/inventory");
        revalidatePath(`/shop/${productId}`);
        revalidatePath("/shop");
        revalidatePath("/");

        return { success: true };
    } catch (error) {
        console.error("Error updating product:", error);
        throw new Error("Failed to update product");
    }
}

export async function deleteProduct(productId: string) {
    console.log(`[ACTION] Deleting product ${productId}...`);
    try {
        const { error } = await supabase
            .from('products')
            .delete()
            .eq('id', productId);

        if (error) throw error;

        revalidatePath("/admin/inventory");
        revalidatePath("/shop");
        revalidatePath("/");
        return { success: true };
    } catch (error) {
        console.error("Error deleting product:", error);
        throw new Error("Failed to delete product");
    }
}

// Collection Management
export async function getCuratedCollections(): Promise<Collection[]> {
    const { data } = await supabase.from('collections').select('*').order('created_at', { ascending: false });

    if (!data) return [];

    return data.map(item => ({
        id: item.id,
        name: item.name,
        subtitle: item.subtitle,
        image: item.image,
        status: item.status,
        productIds: item.product_ids || [],
        itemsCount: (item.product_ids || []).length,
        link: item.link,
        createdAt: item.created_at
    })) as Collection[];
}

export async function getAvailableProducts(): Promise<Product[]> {
    const { data } = await supabase.from('products').select('*').order('created_at', { ascending: false });

    if (!data) return [];

    return data.map(item => ({
        ...item,
        reviewsCount: item.reviews_count // Map DB snake_case to camelCase
    })) as any;
}

export async function createCuratedCollection(formData: FormData) {
    console.log("[ACTION] Creating curated collection...");
    try {
        const id = `col-${Date.now()}`;
        const name = formData.get("name") as string;
        const subtitle = formData.get("subtitle") as string || "";
        const imageFile = formData.get("image") as File | null;
        const status = formData.get("status") as string || 'Active';
        const productIds = JSON.parse(formData.get("productIds") as string || "[]");

        let imageUrl = "";
        if (imageFile && imageFile.size > 0) {
            const savedUrl = await saveFile(imageFile, "collections/");
            if (savedUrl) imageUrl = savedUrl;
        }

        const { error } = await supabase.from('collections').insert([{
            id,
            name,
            subtitle,
            image: imageUrl,
            status,
            product_ids: productIds,
            items_count: productIds.length,
            link: `/collections/${id}`
        }]);

        if (error) throw error;

        revalidatePath("/admin/collections");
        revalidatePath("/");

        return { success: true, id };
    } catch (error) {
        console.error("Error creating collection:", error);
        throw new Error("Failed to create collection");
    }
}

export async function updateCuratedCollection(formData: FormData) {
    const id = formData.get("collectionId") as string;
    console.log(`[ACTION] Updating collection ${id}...`);
    try {
        const name = formData.get("name") as string;
        const subtitle = formData.get("subtitle") as string || "";
        const imageFile = formData.get("image") as File | null;
        const currentImageUrl = formData.get("currentImage") as string || "";
        const status = formData.get("status") as string || 'Active';
        const productIds = JSON.parse(formData.get("productIds") as string || "[]");

        let imageUrl = currentImageUrl;
        if (imageFile && imageFile.size > 0) {
            const savedUrl = await saveFile(imageFile, "collections/");
            if (savedUrl) imageUrl = savedUrl;
        }

        const { error } = await supabase.from('collections').update({
            name,
            subtitle,
            image: imageUrl,
            status,
            product_ids: productIds,
            items_count: productIds.length,
            link: `/collections/${id}`
        }).eq('id', id);

        if (error) throw error;

        revalidatePath("/admin/collections");
        revalidatePath("/");

        return { success: true };
    } catch (error) {
        console.error("Error updating collection:", error);
        throw new Error("Failed to update collection");
    }
}

export async function deleteCollection(id: string) {
    try {
        const { error } = await supabase.from('collections').delete().eq('id', id);
        if (error) throw error;
        revalidatePath("/admin/collections");
        revalidatePath("/");
        return { success: true };
    } catch (error) {
        console.error("Error deleting collection:", error);
        return { success: false, error };
    }
}

// Homepage Management
export async function getHomepageContent() {
    let { data: home } = await supabase.from('homepage_content').select('*').eq('id', 1).single();

    // Auto-sync rubbish data if detected
    if (!home || home.hero?.subtitle === "kbkbb") {
        console.log("[SYNC] Rubbish homepage detected. Syncing from homepage.json...");
        try {
            const jsonPath = path.join(process.cwd(), 'homepage.json');
            if (fs.existsSync(jsonPath)) {
                const homeData = JSON.parse(fs.readFileSync(jsonPath, 'utf8'));
                const { data: synced, error } = await supabase.from('homepage_content').upsert([{
                    id: 1,
                    hero: homeData.hero,
                    promo: homeData.promo,
                    newsletter: homeData.newsletter
                }]).select().single();
                if (!error && synced) home = synced;
            }
        } catch (e) {
            console.error("[SYNC] Failed to sync homepage:", e);
        }
    }

    // Check for rubbish collections
    const { data: checkCol } = await supabase.from('collections').select('id, name').eq('name', 'sadassad');
    if (checkCol && checkCol.length > 0) {
        console.log("[SYNC] Rubbish collections detected. Syncing from collections.json...");
        try {
            const jsonPath = path.join(process.cwd(), 'collections.json');
            if (fs.existsSync(jsonPath)) {
                const colData = JSON.parse(fs.readFileSync(jsonPath, 'utf8'));
                // Clear rubbish collections
                await supabase.from('collections').delete().eq('name', 'sadassad');
                // Insert new ones
                await supabase.from('collections').upsert(colData.map((c: any) => ({
                    id: c.id,
                    name: c.name,
                    subtitle: c.subtitle,
                    image: c.image,
                    status: c.status,
                    link: c.link
                })));
            }
        } catch (e) {
            console.error("[SYNC] Failed to sync collections:", e);
        }
    }

    const { data: collections } = await supabase.from('collections').select('*').eq('status', 'Active').limit(4);
    const { data: products } = await supabase.from('products').select('*').order('popularity', { ascending: false }).limit(8);

    return {
        ...home,
        collections: collections?.map(c => ({
            id: c.id,
            title: c.name,
            subtitle: c.subtitle || "Curated Series",
            image: c.image,
            link: c.link
        })),
        bestSellers: products
    };
}

export async function updateHero(formData: FormData) {
    try {
        const imageFile = formData.get("image") as File | null;
        const currentImage = formData.get("currentImage") as string || "";

        let imageUrl = currentImage;
        if (imageFile && imageFile.size > 0) {
            const savedUrl = await saveFile(imageFile, "homepage/");
            if (savedUrl) imageUrl = savedUrl;
        }

        const data = {
