                    </div>
                ) : collections.length > 0 ? (
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-x-8 gap-y-12">
                        <AnimatePresence mode="popLayout">
                            {collections.map((collection, index) => (
                                <motion.div 
                                    key={collection.id} 
                                    initial={{ opacity: 0, y: 30 }}
