    { id: "details",  title: "Details & Story" },
    { id: "shipping", title: "Shipping & Returns", content: "Complementary standard shipping on all orders. Returns are accepted within 30 days of delivery." },
    { id: "care",     title: "Materials & Care",   content: "Do not wash. Do not bleach. Do not tumble dry. Cool iron if needed. Professional dry clean only." },
] as const;

const TRUST_BADGES = [
    { Icon: Truck,        title: "Free Delivery",  sub: "Orders over $300"  },
    { Icon: ShieldCheck,  title: "2 Year Warranty", sub: "Premium guarantee" },
] as const;

// خ“أ¶أ‡خ“أ¶أ‡ Types خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡

