    }, [effectiveColor, selectedSize, product.imageVariants]);

    // خ“أ¶أ‡خ“أ¶أ‡ Add to Cart خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡
    const addToCartTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

    const handleAddToCart = useCallback(() => {
        if (!selectedSize) {
            setAlertModal({ 
                open: true, 
                title: "Selection Required", 
                desc: "Please select a size before adding to cart." 
            });
            return;
        }
        addItem({
            productId: product.id,
            name:      product.name,
            price:     product.price,
            image:     product.images[0],
            size:      selectedSize,
            color:     effectiveColor,
            quantity,
        });
        setAdded(true);
        if (addToCartTimer.current) clearTimeout(addToCartTimer.current);
        addToCartTimer.current = setTimeout(() => setAdded(false), 2000);
    }, [selectedSize, effectiveColor, quantity, addItem, product]);

    // Cleanup timer on unmount
    useEffect(() => () => { if (addToCartTimer.current) clearTimeout(addToCartTimer.current); }, []);

    // خ“أ¶أ‡خ“أ¶أ‡ Sticky bar via IntersectionObserver (zero scroll-listener overhead) خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡
    useEffect(() => {
        const btn = document.getElementById("main-add-to-cart");
        if (!btn) return;
        const observer = new IntersectionObserver(
            ([entry]) => setShowStickyBar(!entry.isIntersecting),
            { threshold: 0 }
        );
        observer.observe(btn);
        return () => observer.disconnect();
    }, []);

    // خ“أ¶أ‡خ“أ¶أ‡ Quantity helpers خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡
    const decrement = useCallback(() => setQuantity((q) => Math.max(1, q - 1)), []);
    const increment = useCallback(() => setQuantity((q) => q + 1), []);

    const toggleAccordion = useCallback(
        (id: string) => setOpenAccordion((prev) => (prev === id ? "" : id)),
        []
    );

    // خ“أ¶أ‡خ“أ¶أ‡ Rating stars خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡
    const rating     = product.rating ?? 0;
    const ratingFloor = Math.floor(rating);

    // خ“أ¶أ‡خ“أ¶أ‡ Render خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡خ“أ¶أ‡
    return (
        <div className="flex flex-col">
            {/* Header */}
            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.6 }}
