// Orders
export async function getOrdersDB(): Promise<any[]> {
  const { data, error } = await supabase
    .from('orders')
    .select('*')
    .order('created_at', { ascending: false });

  if (error) return [];

  return data.map(o => ({
    ...o,
    customer: o.customer_name,
    total: o.total_amount,
    items: o.items_count,
    date: new Date(o.created_at).toLocaleDateString()
  }));
}

